from pathlib import Path
p=Path('output/github-pages-papiamento/index.html')
text=p.read_text()
text=text.replace('.layout { display:grid; grid-template-columns: minmax(250px, 320px) minmax(0,1fr); gap:var(--space-6); align-items:start; }','.layout { display:grid; grid-template-columns: minmax(220px, 280px) minmax(0,1fr); gap:var(--space-6); align-items:start; }')
text=text.replace('.sidebar { padding:var(--space-5); position:sticky; top:var(--space-4); align-self:start; display:grid; gap:var(--space-5); overflow:hidden; max-height: calc(100vh - var(--space-8)); }','.sidebar { padding:var(--space-5); position:sticky; top:var(--space-4); align-self:start; display:grid; gap:var(--space-5); overflow:auto; max-height: calc(100vh - var(--space-8)); min-width:0; }')
text=text.replace('@media (max-width: 1200px) { .layout { grid-template-columns: 260px minmax(0,1fr); } }\n    @media (max-width: 980px) { .layout, .hero, .skills-grid, .word-grid, .activity-grid, .choice-group { grid-template-columns: 1fr; } .sidebar { position:static; max-height:none; } .mini-progress { grid-template-columns: 1fr; } }\n    @media (max-width: 640px) { .app-shell { padding: var(--space-3); } .panel, .sidebar { padding: var(--space-4); } .topbar { align-items:flex-start; flex-direction:column; } .top-actions { width:100%; } .pill, .theme-toggle { flex:1 1 auto; } }\n    @media (min-width: 981px) and (max-width: 1200px) { .sidebar { position:sticky; top:var(--space-3); } }','@media (max-width: 1280px) { .layout { grid-template-columns: minmax(200px, 250px) minmax(0,1fr); } }\n    @media (max-width: 1100px) { .layout { grid-template-columns: minmax(180px, 220px) minmax(0,1fr); gap:var(--space-4); } .sidebar { top:var(--space-3); } }\n    @media (max-width: 900px) { .layout { grid-template-columns: 1fr; } .sidebar { position:static; max-height:none; } .mini-progress { grid-template-columns: 1fr; } }\n    @media (max-width: 640px) { .app-shell { padding: var(--space-3); } .panel, .sidebar { padding: var(--space-4); } .topbar { align-items:flex-start; flex-direction:column; } .top-actions { width:100%; } .pill, .theme-toggle { flex:1 1 auto; } }')
p.write_text(text)
print('layout updated')
